import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface FunnelStage {
  stage: string;
  currentRate: number;
  previousRate: number;
}

interface FunnelData {
  funnelStages: FunnelStage[];
  comparison: {
    timePeriod: string;
    overallChange: number;
  };
}

interface Meta {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const funnelData = response.data as FunnelData;
  const metaData = response.meta as Meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              Conversion Funnel
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 1 }}>
              {funnelData.comparison.timePeriod} Comparison
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center' }}>
              {funnelData.comparison.overallChange >= 0 ? (
                <TrendingUp sx={{ color: '#4CAF50', mr: 0.5 }} />
              ) : (
                <TrendingDown sx={{ color: '#E53935', mr: 0.5 }} />
              )}
              <Typography variant="body2" sx={{ color: funnelData.comparison.overallChange >= 0 ? '#4CAF50' : '#E53935' }}>
                {funnelData.comparison.overallChange}%
              </Typography>
            </Box>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: funnelData.funnelStages.map(stage => stage.currentRate),
                color: metaData.primaryColor,
              },
            ]}
            xAxis={[
              {
                data: funnelData.funnelStages.map(stage => stage.stage),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 12,
                  fill: '#B0BEC5',
                },
              },
            ]}
            margin={{ top: 10, bottom: 40, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {funnelData.funnelStages.map((stage, index) => (
              <Chip
                key={index}
                label={`${stage.stage}: ${stage.currentRate}%`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: metaData.accentColor, color: '#1E1E1E' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
